'''
Generates critical_issue_status_2026-03-26.pptx from the root-cause-clustered
bug data. Matches the existing slide template style (purple headers, white rows).

Usage:
    python generate_critical_issue_slides.py

Output:
    critical_issue_status_2026-03-26.pptx in the same directory as this script.
'''

import os
from pptx import Presentation
from pptx.util import Inches, Pt, Emu
from pptx.dml.color import RGBColor
from pptx.enum.text import PP_ALIGN, MSO_ANCHOR
from pptx.oxml.ns import qn

# --- Color constants matching the existing template ---
PURPLE_HEADER = RGBColor(0x7B, 0x2D, 0x8E)  # Purple from the screenshot
WHITE = RGBColor(0xFF, 0xFF, 0xFF)
BLACK = RGBColor(0x00, 0x00, 0x00)
DARK_GRAY = RGBColor(0x33, 0x33, 0x33)
LIGHT_GRAY_BG = RGBColor(0xF2, 0xF2, 0xF2)  # Alternating row shading
CORNELIS_BLUE = RGBColor(0x00, 0x3D, 0x6B)   # Cornelis brand navy

JIRA_BASE = 'https://cornelisnetworks.atlassian.net/browse/'

# --- Slide dimensions (widescreen 16:9) ---
SLIDE_WIDTH = Inches(13.333)
SLIDE_HEIGHT = Inches(7.5)


def set_cell_fill(cell, color):
    '''Set solid fill color on a table cell.'''
    tc = cell._tc
    tcPr = tc.get_or_add_tcPr()
    # Remove any existing fill
    for child in list(tcPr):
        if child.tag.endswith('}solidFill') or child.tag.endswith('}noFill'):
            tcPr.remove(child)
    solidFill = tcPr.makeelement(qn('a:solidFill'), {})
    srgbClr = solidFill.makeelement(qn('a:srgbClr'), {'val': '%02X%02X%02X' % (color[0], color[1], color[2])})
    solidFill.append(srgbClr)
    tcPr.append(solidFill)


def set_cell_border(cell, color=RGBColor(0xCC, 0xCC, 0xCC), width=Pt(0.5)):
    '''Set thin borders on a cell.'''
    tc = cell._tc
    tcPr = tc.get_or_add_tcPr()
    for edge in ['lnL', 'lnR', 'lnT', 'lnB']:
        ln = tcPr.makeelement(qn('a:%s' % edge), {'w': str(int(width))})
        solidFill = ln.makeelement(qn('a:solidFill'), {})
        srgbClr = solidFill.makeelement(qn('a:srgbClr'), {'val': '%02X%02X%02X' % (color[0], color[1], color[2])})
        solidFill.append(srgbClr)
        ln.append(solidFill)
        # Remove existing same-tag element
        for existing in list(tcPr):
            if existing.tag == ln.tag:
                tcPr.remove(existing)
        tcPr.append(ln)


def format_cell(cell, text, font_size=Pt(9), bold=False, color=DARK_GRAY, alignment=PP_ALIGN.LEFT):
    '''Set text content and formatting on a table cell.'''
    cell.text = ''
    tf = cell.text_frame
    tf.word_wrap = True
    tf.auto_size = None
    # Reduce margins for tighter layout
    tf.margin_left = Pt(3)
    tf.margin_right = Pt(3)
    tf.margin_top = Pt(2)
    tf.margin_bottom = Pt(2)
    cell.vertical_anchor = MSO_ANCHOR.TOP

    p = tf.paragraphs[0]
    p.alignment = alignment
    p.space_before = Pt(0)
    p.space_after = Pt(0)
    run = p.add_run()
    run.text = text
    run.font.size = font_size
    run.font.bold = bold
    run.font.color.rgb = color


def format_header_cell(cell, text, font_size=Pt(9)):
    '''Format a header cell with purple background and white bold text.'''
    set_cell_fill(cell, PURPLE_HEADER)
    format_cell(cell, text, font_size=font_size, bold=True, color=WHITE)


def add_hyperlink_cell(cell, items, font_size=Pt(8)):
    '''Add cell content with Jira ticket IDs as hyperlinks.
    items is a list of (ticket_id, display_text) tuples, or just strings.
    '''
    cell.text = ''
    tf = cell.text_frame
    tf.word_wrap = True
    tf.margin_left = Pt(3)
    tf.margin_right = Pt(3)
    tf.margin_top = Pt(2)
    tf.margin_bottom = Pt(2)
    cell.vertical_anchor = MSO_ANCHOR.TOP

    p = tf.paragraphs[0]
    p.space_before = Pt(0)
    p.space_after = Pt(0)

    for i, item in enumerate(items):
        if i > 0:
            run = p.add_run()
            run.text = '\n'
            run.font.size = font_size

        if isinstance(item, tuple):
            ticket_id, display = item
            run = p.add_run()
            run.text = display
            run.font.size = font_size
            run.font.color.rgb = CORNELIS_BLUE
            run.font.underline = True
            # Add hyperlink via XML
            rPr = run._r.get_or_add_rPr()
            hlinkClick = rPr.makeelement(qn('a:hlinkClick'), {
                qn('r:id'): ''
            })
            rPr.append(hlinkClick)
            # Create relationship
            url = JIRA_BASE + ticket_id
            part = cell._tc.getparent().getparent().getparent().getparent()
            # We'll handle hyperlinks via the slide relationship
        else:
            run = p.add_run()
            run.text = item
            run.font.size = font_size
            run.font.color.rgb = DARK_GRAY


def add_table(slide, left, top, width, height, rows, cols):
    '''Add a table shape to a slide and return the table object.'''
    table_shape = slide.shapes.add_table(rows, cols, left, top, width, height)
    return table_shape.table


def add_title(slide, text, left=Inches(0.5), top=Inches(0.2), width=Inches(12), height=Inches(0.5)):
    '''Add a title text box to a slide.'''
    txBox = slide.shapes.add_textbox(left, top, width, height)
    tf = txBox.text_frame
    p = tf.paragraphs[0]
    run = p.add_run()
    run.text = text
    run.font.size = Pt(20)
    run.font.bold = True
    run.font.color.rgb = CORNELIS_BLUE
    return txBox


def add_subtitle(slide, text, left=Inches(0.5), top=Inches(0.65), width=Inches(12), height=Inches(0.35)):
    '''Add subtitle text below the title.'''
    txBox = slide.shapes.add_textbox(left, top, width, height)
    tf = txBox.text_frame
    p = tf.paragraphs[0]
    run = p.add_run()
    run.text = text
    run.font.size = Pt(11)
    run.font.color.rgb = DARK_GRAY
    return txBox


