def create_presentation():
    '''Build the full PowerPoint presentation.'''
    prs = Presentation()
    # Set 16:9 widescreen
    prs.slide_width = SLIDE_WIDTH
    prs.slide_height = SLIDE_HEIGHT

    # Use blank layout
    blank_layout = prs.slide_layouts[6]  # Blank

    # ===== SLIDE 1: Scoreboard + Rollup =====
    slide = prs.slides.add_slide(blank_layout)
    add_title(slide, 'Critical Issue Status \u2014 2026-03-26')
    add_subtitle(slide, 'Source: Jira filter "SW 12.1.2 Targeted P0/P1 Bugs" (33573)  |  33 bugs: 23 P0, 10 P1  |  20 active, 9 Verify, 4 Closed')

    # Scoreboard row
    sb_left = Inches(0.5)
    sb_top = Inches(1.05)
    sb_width = Inches(10.0)
    sb_height = Inches(0.55)
    sb_table = add_table(slide, sb_left, sb_top, sb_width, sb_height, 2, 4)

    sb_headers = ['Open Critical', 'New This Week', 'Waiting for Verify in DST', 'Actively Root-Causing']
    sb_values = ['20', '5', '9', '12']
    for i, (h, v) in enumerate(zip(sb_headers, sb_values)):
        sb_table.columns[i].width = Inches(2.5)
        format_header_cell(sb_table.cell(0, i), h, font_size=Pt(10))
        sb_table.cell(0, i).text_frame.paragraphs[0].alignment = PP_ALIGN.CENTER
        format_cell(sb_table.cell(1, i), v, font_size=Pt(18), bold=True, color=CORNELIS_BLUE, alignment=PP_ALIGN.CENTER)
        set_cell_fill(sb_table.cell(1, i), WHITE)

    # Rollup table
    headers, rows = build_rollup_table_data()
    n_rows = len(rows) + 1  # +1 for header
    n_cols = len(headers)
    tbl_left = Inches(0.3)
    tbl_top = Inches(1.75)
    tbl_width = Inches(12.7)
    tbl_height = Inches(5.5)

    table = add_table(slide, tbl_left, tbl_top, tbl_width, tbl_height, n_rows, n_cols)

    # Column widths: Area, Issues, Description, Customer, Status, Next Steps
    col_widths = [1.1, 1.0, 3.8, 0.9, 0.9, 5.0]
    for i, w in enumerate(col_widths):
        table.columns[i].width = Inches(w)

    # Header row
    for i, h in enumerate(headers):
        format_header_cell(table.cell(0, i), h, font_size=Pt(9))

    # Data rows
    for r_idx, row in enumerate(rows):
        for c_idx, val in enumerate(row):
            cell = table.cell(r_idx + 1, c_idx)
            is_bold = (c_idx == 0)  # Bold the area column
            font_size = Pt(8) if c_idx in (2, 5) else Pt(8)
            format_cell(cell, val, font_size=font_size, bold=is_bold, color=DARK_GRAY)
            # Alternate row shading
            if r_idx % 2 == 1:
                set_cell_fill(cell, LIGHT_GRAY_BG)
            else:
                set_cell_fill(cell, WHITE)
            set_cell_border(cell)

    # ===== DETAIL SLIDES =====
    detail_slides = build_detail_data()

    for detail in detail_slides:
        slide = prs.slides.add_slide(blank_layout)
        add_title(slide, detail['title'])
        add_subtitle(slide, detail['subtitle'])

        current_top = Inches(1.1)

        for section in detail['sections']:
            # Section label
            label_box = slide.shapes.add_textbox(Inches(0.5), current_top, Inches(8), Inches(0.3))
            tf = label_box.text_frame
            p = tf.paragraphs[0]
            run = p.add_run()
            run.text = section['label']
            run.font.size = Pt(11)
            run.font.bold = True
            run.font.color.rgb = DARK_GRAY
            current_top += Inches(0.35)

            headers = section['headers']
            rows = section['rows']
            col_widths = section['col_widths']
            n_rows = len(rows) + 1
            n_cols = len(headers)

            # Calculate total width from col_widths
            total_w = sum(col_widths)
            # Scale to fit 12.3 inches
            scale = 12.3 / total_w
            scaled_widths = [w * scale for w in col_widths]

            # Estimate row height: ~0.35 per row for detail tables
            row_h = 0.35
            tbl_height = Inches(min((n_rows * row_h), 4.0))

            table = add_table(slide, Inches(0.5), current_top, Inches(12.3), tbl_height, n_rows, n_cols)

            for i, w in enumerate(scaled_widths):
                table.columns[i].width = Inches(w)

            # Header
            for i, h in enumerate(headers):
                format_header_cell(table.cell(0, i), h, font_size=Pt(8))

            # Data
            for r_idx, row in enumerate(rows):
                for c_idx, val in enumerate(row):
                    cell = table.cell(r_idx + 1, c_idx)
                    # First column (Issue) gets special treatment for ticket IDs
                    is_bold = False
                    font_sz = Pt(8)
                    format_cell(cell, val, font_size=font_sz, bold=is_bold, color=DARK_GRAY)
                    if r_idx % 2 == 1:
                        set_cell_fill(cell, LIGHT_GRAY_BG)
                    else:
                        set_cell_fill(cell, WHITE)
                    set_cell_border(cell)

                    # Add hyperlink for Issue column (first column with STL- prefix)
                    if c_idx == 0 and val.startswith('STL-'):
                        # Make it look like a link
                        cell.text_frame.paragraphs[0].runs[0].font.color.rgb = CORNELIS_BLUE
                        cell.text_frame.paragraphs[0].runs[0].font.underline = True
                        # Add actual hyperlink
                        run_elem = cell.text_frame.paragraphs[0].runs[0]._r
                        rPr = run_elem.get_or_add_rPr()
                        hlinkClick = rPr.makeelement(qn('a:hlinkClick'), {})
                        url = JIRA_BASE + val
                        rel = slide.part.relate_to(url, 'http://schemas.openxmlformats.org/officeDocument/2006/relationships/hyperlink', is_external=True)
                        hlinkClick.set(qn('r:id'), rel)
                        rPr.append(hlinkClick)

            current_top += tbl_height + Inches(0.2)

    # ===== SLIDE 7: Root Cause Cluster Summary =====
    slide = prs.slides.add_slide(blank_layout)
    add_title(slide, 'Root Cause Cluster Summary')
    add_subtitle(slide, '20 active bugs \u2192 7 root causes + 5 standalone')

    rc_headers = ['#', 'Root Cause', 'Active', 'Verify', 'Closed', 'Fix One, Fix All?']
    rc_rows = [
        ['1', 'BTS DMA-buf deregistration race', '3', '6', '1', 'Yes \u2014 76950 fix in review \u2192 cascade-fixes. But 2 of 3 blockers still Open.'],
        ['2', 'OPX TID cache kernel divergence', '2', '1', '\u2014', 'Yes \u2014 same arch fix. Complex (user + kernel).'],
        ['3', 'MYR buffer/credit switch FW', '4', '\u2014', '\u2014', 'Partially \u2014 related but may need separate fixes. Zero resolved.'],
        ['4', 'IPoIB / SDMA transmit', '2', '\u2014', '\u2014', 'Maybe \u2014 74848 sw_fixed may resolve 76836.'],
        ['5', 'PCIe / card init', '3', '\u2014', '\u2014', 'Partially \u2014 75661 + 76323 same path, 76997 is runtime.'],
        ['6', 'OPX GPU AI', '1', '\u2014', '2', 'TBD \u2014 77071 may be user config.'],
        ['7', 'OPX perf regression', '1', '1', '1', 'Separate \u2014 bisecting to isolate commit.'],
        ['8', 'Link training 8051 FW', '1', '\u2014', '\u2014', 'Standalone. Link WG owns.'],
        ['\u2014', 'Standalone (Lustre non-BTS, VR, BMC, CI, SRIOV)', '4', '2', '\u2014', 'Each separate.'],
    ]

    n_rows = len(rc_rows) + 1
    n_cols = len(rc_headers)
    table = add_table(slide, Inches(0.5), Inches(1.1), Inches(12.3), Inches(4.0), n_rows, n_cols)

    rc_col_widths = [0.3, 2.5, 0.6, 0.6, 0.6, 7.7]
    for i, w in enumerate(rc_col_widths):
        table.columns[i].width = Inches(w)

    for i, h in enumerate(rc_headers):
        format_header_cell(table.cell(0, i), h, font_size=Pt(9))

    for r_idx, row in enumerate(rc_rows):
        for c_idx, val in enumerate(row):
            cell = table.cell(r_idx + 1, c_idx)
            bold = (c_idx == 1)
            align = PP_ALIGN.CENTER if c_idx in (0, 2, 3, 4) else PP_ALIGN.LEFT
            format_cell(cell, val, font_size=Pt(9), bold=bold, color=DARK_GRAY, alignment=align)
            if r_idx % 2 == 1:
                set_cell_fill(cell, LIGHT_GRAY_BG)
            else:
                set_cell_fill(cell, WHITE)
            set_cell_border(cell)

    # Key Callouts box
    callout_top = Inches(5.3)
    callout_box = slide.shapes.add_textbox(Inches(0.5), callout_top, Inches(12.3), Inches(2.0))
    tf = callout_box.text_frame
    tf.word_wrap = True

    callouts = [
        'BTS is #1 area \u2014 3 active + 6 in Verify. 76950 fix depends on 2 patches still Open (76983, 76984). Next DST is the gate.',
        'MYR buffer/credit is riskiest \u2014 4 bugs, all In Progress, zero fixes landed. TACC is primary customer.',
        '76836 (LLNL ipoib) may be fabric-caused \u2014 test SDMA fix first; if no resolution, reclassify.',
        'OPX TID hangs still chronic \u2014 73247 open since 12.1.0.x. Architecturally complex fix.',
        '75661 (Lenovo power-cycle) needs pickup \u2014 assigned to Zhang, Open, no recent activity.',
    ]

    for i, text in enumerate(callouts):
        if i == 0:
            p = tf.paragraphs[0]
        else:
            p = tf.add_paragraph()
        p.space_before = Pt(2)
        p.space_after = Pt(2)
        # Bullet number
        run = p.add_run()
        run.text = '%d. %s' % (i + 1, text)
        run.font.size = Pt(9)
        run.font.color.rgb = DARK_GRAY

    # Save
    output_dir = os.path.dirname(os.path.abspath(__file__))
    output_path = os.path.join(output_dir, 'critical_issue_status_2026-03-26.pptx')
    prs.save(output_path)
    print('Saved: %s' % output_path)
    return output_path


